#include "gpu_recursive_reduce.h"

// Placeholder kernel to simulate the rest of the application
__global__ void simulateKernel(int *output) {
    output[threadIdx.x] = threadIdx.x;
}

int main() {
    int N = 8;
    int *h_data = new int[N];
    int *d_data, *d_odata;

    cudaMalloc(&d_data, N * sizeof(int));
    cudaMalloc(&d_odata, (N / 2) * sizeof(int));

    // Initialize h_data with some values
    for (int i = 0; i < N; ++i) {
        h_data[i] = i;
    }

    cudaMemcpy(d_data, h_data, N * sizeof(int), cudaMemcpyHostToDevice);

    // Call the kernel
    dim3 blockSize(32);
    dim3 gridSize((N + blockSize.x - 1) / blockSize.x);
    gpuRecursiveReduce<<<gridSize, blockSize, blockSize.x * sizeof(int)>>>(d_data, d_odata, N);
    cudaDeviceSynchronize();

    // Copy result back to host
    int *h_odata = new int[N / 2];
