__global__ void k_GeoDistance(double *lat1, double *lon1, double *lat2, double *lon2, double *result, int n) {
    int idx = blockIdx.x * blockDim.x + threadIdx.x;
    if (idx >= n) return;

    double dLat = (lat2[idx] - lat1[idx]) * FACTOR;
    double dLon = (lon2[idx] - lon1[idx]) * FACTOR;
    double a = sin(dLat / 2) * sin(dLat / 2) +
               cos(lat1[idx] * FACTOR) * cos(lat2[idx] * FACTOR) *
               sin(dLon / 2) * sin(dLon / 2);
    double c = 2 * atan2(sqrt(a), sqrt(1 - a));
    result[idx] = R * c;
}
