#include "signal_power.h"

#define ARRAY_SIZE 10
#define TOLERANCE  1e-2

// Macro for CUDA error checking
#define CUDA_CHECK(call) {                                                        \
        cudaError_t err = call;                                                   \
        if (err != cudaSuccess) {                                                 \
            fprintf(stderr, "CUDA error in file '%s' in line %d: %s.\n",          \
                    __FILE__, __LINE__, cudaGetErrorString(err));                 \
            exit(EXIT_FAILURE);                                                   \
        }                                                                         \
}

// Struct to define test cases
struct TestCase {
    float inputSignal_h[ARRAY_SIZE];
    float expectedOutput_h[ARRAY_SIZE];
};

void launch() {
    // Create a CUDA stream
    cudaStream_t stream;
    CUDA_CHECK(cudaStreamCreate(&stream));

    // Allocate device memory once for the largest dataset
    float* inputSignal_d;
    float* outputSignal_d;
    size_t arrayBytes = ARRAY_SIZE * sizeof(float);

    CUDA_CHECK(cudaMallocAsync((void**)&inputSignal_d, arrayBytes, stream));
    CUDA_CHECK(cudaMallocAsync((void**)&outputSignal_d, arrayBytes, stream));

    // Define execution configuration
    int threadsPerBlock = 16;
    int blocksPerGrid = (ARRAY_SIZE + threadsPerBlock - 1) / threadsPerBlock;
    int size = ARRAY_SIZE;

    // Define all test cases
    TestCase testCases[] = {
        // Test Case 1
        {
            { 0.0f, 1.0f, 2.0f, 3.0f, 4.0f, 5.0f, 6.0f, 7.0f, 8.0f, 9.0f },
            { 0.0f, 1.0f, 4.0f, 9.0f, 16.0f, 25.0f, 36.0f, 49.0f, 64.0f, 81.0f }
        },
