    for (int tc = 0; tc < numTestCases; tc++) {
        void* kernelArgs[] = { &outputSignal_d, &inputSignal_d, &size };

        // Copy input data to device asynchronously
        CUDA_CHECK(cudaMemcpyAsync(inputSignal_d, testCases[tc].inputSignal_h, arrayBytes, cudaMemcpyHostToDevice, stream));

        // Launch the kernel asynchronously using cudaLaunchKernel
        // Grid: (ceil(ARRAY_SIZE / 16), 1, 1)
        // Block: (16, 1, 1)
        CUDA_CHECK(cudaLaunchKernel((const void*)k_computeSignalPower, dim3(blocksPerGrid), dim3(threadsPerBlock), kernelArgs, 0, stream));

        // Copy output data back to host asynchronously
        float outputSignal_h[ARRAY_SIZE];
        CUDA_CHECK(cudaMemcpyAsync(outputSignal_h, outputSignal_d, arrayBytes, cudaMemcpyDeviceToHost, stream));

        // Synchronize to ensure all operations for the current test case are complete
        CUDA_CHECK(cudaStreamSynchronize(stream));

        // Verify the results
        for (int i = 0; i < ARRAY_SIZE; i++) {
            assert(abs(outputSignal_h[i] - testCases[tc].expectedOutput_h[i]) < TOLERANCE);
        }
    }

    // Free device memory asynchronously
    CUDA_CHECK(cudaFreeAsync(inputSignal_d, stream));
    CUDA_CHECK(cudaFreeAsync(outputSignal_d, stream));

    // Destroy the CUDA stream
    CUDA_CHECK(cudaStreamDestroy(stream));
