#include "gpu_recursive_reduce.h"

__global__ void gpuRecursiveReduce(int *g_idata, int *g_odata, unsigned int isize) {
    extern __shared__ int sdata[];

    unsigned int tid = threadIdx.x;
    unsigned int i = blockIdx.x * blockDim.x + threadIdx.x;

    if (i < isize) {
        sdata[tid] = g_idata[i];
    } else {
        sdata[tid] = 0;
    }
    __syncthreads();

    for (unsigned int s = 1; s < blockDim.x; s *= 2) {
        if (tid % (2 * s) == 0) {
            sdata[tid] += sdata[tid + s];
        }
        __syncthreads();
    }

    if (tid == 0) {
        g_odata[blockIdx.x] = sdata[0];
    }

    if (blockCount > 1 && blockIdx.x % 2 == 0) {
        extern __shared__ int temp[];

        unsigned int offset = 0;
        while (offset < gridSize) {
            unsigned int blockId = blockIdx.x / 2 + offset;
            if (blockId < blockCount / 2) {
                temp[tid] = g_odata[blockIdx.x] + g_odata[blockIdx.x + 1];
                __syncthreads();
                g_odata[blockId] = temp[tid];
            }
            offset <<= 1;
            __syncthreads();
        }
    }
}

